import scala.collection.mutable

def solve(c: Long, connections: Array[Array[Long]], queries: Array[Array[Long]]): Array[Long] = {
    val n = c.toInt
    val graph = Array.fill(n + 1)(mutable.ListBuffer[Int]())

    for (conn <- connections) {
        val u = conn(0).toInt
        val v = conn(1).toInt
        if (u != v) {
            graph(u) += v
            graph(v) += u
        }
    }

    val compId = Array.ofDim[Int](n + 1)
    var compIndex = 0
    val queue = mutable.Queue[Int]()

    for (i <- 1 to n) {
        if (compId(i) == 0) {
            compIndex += 1
            queue.enqueue(i)
            compId(i) = compIndex
            while (queue.nonEmpty) {
                val node = queue.dequeue()
                for (neighbor <- graph(node)) {
                    if (compId(neighbor) == 0) {
                        compId(neighbor) = compIndex
                        queue.enqueue(neighbor)
                    }
                }
            }
        }
    }

    val compSets = mutable.Map[Int, mutable.TreeSet[Long]]()
    for (i <- 1 to n) {
        val cid = compId(i)
        val set = compSets.getOrElseUpdate(cid, mutable.TreeSet[Long]())
        set += i.toLong
    }

    val onlineStatus = Array.fill[Boolean](n + 1)(true)

    val result = mutable.ArrayBuffer[Long]()

    for (q <- queries) {
        val op = q(0)
        val x = q(1)
        val xInt = x.toInt
        if (op == 2) {
            if (onlineStatus(xInt)) {
                onlineStatus(xInt) = false
                val cid = compId(xInt)
                compSets(cid) -= x
            }
        } else if (op == 1) {
            if (onlineStatus(xInt)) {
                result += x
            } else {
                val cid = compId(xInt)
                val set = compSets(cid)
                if (set.isEmpty) {
                    result += -1L
                } else {
                    result += set.head
                }
            }
        }
    }

    result.toArray
}
```

